INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (311, 8, 11, 0.5, 0, 311006, 0, "疼く……疼くぞ！\n我が魔眼が新たなる年を祝えと……！", 0, 100911, 0);
INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (311, "", 91, "", "", 311007, "", "", "", 311006, "");
