INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (312, 1, 3, "", 0.2, 312006, "", "nop_talk_surprise_kira", "", 101611, "");
