INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (513, 5, 11, 0.5, 0, 513048, 0, "クウカはこんな新年早々に\n豪華な料理とたくさんの人の前で\nドSさんに弄ばれ辱めを……！\nぐふふ……ぐふふふふ。", 1, 104511, 0);
INSERT INTO `v1_3bb095ecb89e4fd573c67cf01f415e501214fc94fd92b1c2062d53c3a3f54176` VALUES (513, 1, 3, "", 0.2, 513049, "", "nop_13_kuka_talk_memory1", "", 104511, "");
